#!/usr/bin/env node
/**
 * Wraps gifenc's CJS dist so it can be loaded by the playground GIF encoder
 * Web Worker via `importScripts(...)`.
 *
 * Output: public/playground/gifenc.bundle.js
 * Run: node scripts/bundle-gifenc-worker.mjs   (also runs in prebuild)
 */
import { readFile, writeFile, mkdir } from "node:fs/promises";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const SRC = join(ROOT, "node_modules", "gifenc", "dist", "gifenc.js");
const OUT_DIR = join(ROOT, "public", "playground");
const OUT = join(OUT_DIR, "gifenc.bundle.js");

const src = await readFile(SRC, "utf8");

// Strip sourcemap reference (worker won't need it)
const cleaned = src.replace(/\/\/# sourceMappingURL=.*$/m, "").trim();

const wrapped = `// Generated by scripts/bundle-gifenc-worker.mjs from node_modules/gifenc.
// Exposes \`self.gifenc\` for use in the playground GIF encoder Web Worker.
(function(){
  var module = { exports: {} };
  var exports = module.exports;
${cleaned}
  self.gifenc = module.exports;
})();
`;

await mkdir(OUT_DIR, { recursive: true });
await writeFile(OUT, wrapped);
console.log(`✓ Wrote public/playground/gifenc.bundle.js (${wrapped.length} bytes)`);
